            code: `import numpy as np

def cosine_similarity(v1, v2):
    dot_prod = np.dot(v1, v2)
    norm_v1 = np.linalg.norm(v1)
    norm_v2 = np.linalg.norm(v2)
    return dot_prod / (norm_v1 * norm_v2)

# Simulated low-dimensional dummy representations
embeddings = {
    "king":  np.array([0.90, 0.10, 0.05]),
    "man":   np.array([0.85, 0.05, 0.02]),
    "woman": np.array([0.15, 0.80, 0.01]),
    "queen": np.array([0.20, 0.92, 0.04])
}

# Linear translation math
target_vector = embeddings["king"] - embeddings["man"] + embeddings["woman"]
score = cosine_similarity(target_vector, embeddings["queen"])

print(f"Cosine Similarity to 'queen': {score:.4f}")`,
