            code: `import numpy as np

def get_positional_encoding(seq_len, d_model):
    # Initialize the encoding matrix
    pe = np.zeros((seq_len, d_model))
    
    # Compute the positional values
    position = np.arange(seq_len)[:, np.newaxis]
    div_term = np.exp(np.arange(0, d_model, 2) * -(np.log(10000.0) / d_model))
    
    # Assign alternating sine and cosine functions
    pe[:, 0::2] = np.sin(position * div_term)
    pe[:, 1::2] = np.cos(position * div_term)
    
    return pe

# Run Verification
pe_matrix = get_positional_encoding(seq_len=10, d_model=64)
print(f"Generated Positional Matrix Shape: {pe_matrix.shape}")`,
