            code: `import numpy as np

def scaled_dot_product_attention(Q, K, V):
    # Compute raw score alignments
    matmul_qk = np.dot(Q, K.T)
    
    # Scale scores based on dimensionality
    dk = Q.shape[-1]
    scaled_attention_logits = matmul_qk / np.sqrt(dk)
    
    # Row-wise softmax normalization
    exp_logits = np.exp(scaled_attention_logits - np.max(scaled_attention_logits, axis=-1, keepdims=True))
    attention_weights = exp_logits / np.sum(exp_logits, axis=-1, keepdims=True)
    
    # Weighted calculation over Values
    output = np.dot(attention_weights, V)
    return output, attention_weights

# Sample Execution Setup
np.random.seed(42)
Q = np.random.randn(3, 4) # 3 tokens, dimension 4
K = np.random.randn(3, 4)
V = np.random.randn(3, 4)

output, weights = scaled_dot_product_attention(Q, K, V)
print("Attention Weights Matrix:\\n", np.round(weights, 4))`,
