            code: `import numpy as np

def rank_semantic_chunks(query_vector, document_embeddings, top_k=2):
    q = np.array(query_vector)
    d_matrix = np.array(document_embeddings)
    
    # Calculate row-wise dot product similarity over normalized structures
    scores = np.dot(d_matrix, q) / (np.linalg.norm(d_matrix, axis=1) * np.linalg.norm(q))
    
    # Isolate indices in descending order
    top_indices = np.argsort(scores)[::-1][:top_k]
    return [(idx, scores[idx]) for idx in top_indices]

# Test Data Mocking
mock_query = [0.1, 0.9, 0.0, 0.2]
mock_docs = [
    [0.12, 0.88, 0.01, 0.18], # High match
    [0.85, 0.05, 0.10, 0.02], # Low match
    [0.15, 0.82, 0.05, 0.22]  # Moderate match
]
print("Top matched indices and scores:", rank_semantic_chunks(mock_query, mock_docs))`,
